static void pcibase_realize(PCIDevice *pdev, Error **errp)
{
    PCIBaseState *s = PCIBASE_DEVICE(pdev);
    uint8_t *pci_conf = pdev->config;

    /* set IRQ pin A */
    pci_config_set_interrupt_pin(pci_conf, 1);

    /* BAR0 IO, BAR1 MMIO as in driver probe */
    s->num_bars = 2;
    s->bar_info[0].index = 0;
    s->bar_info[0].type = BAR_TYPE_PIO;
    s->bar_info[0].size = 0x100;
    s->bar_info[0].name = "adm8211-io";
    s->bar_info[0].sparse = false;

    s->bar_info[1].index = 1;
    s->bar_info[1].type = BAR_TYPE_MMIO;
    s->bar_info[1].size = ADM8211_MMIO_SIZE;
    s->bar_info[1].name = "adm8211-mmio";
    s->bar_info[1].sparse = false;

    s->mmio_backing_size = ADM8211_MMIO_SIZE;
    s->mmio_backing = g_malloc0(s->mmio_backing_size);

    for (int i = 0; i < s->num_bars; i++) {
        pcibase_register_bar(pdev, s, &s->bar_info[i], errp);
        if (errp && *errp) {
            return;
        }
    }

    pcibase_dma_device_realize(pdev, errp);
    if (errp && *errp) {
        return;
    }

    /* Initialize EEPROM contents with minimal values so that the driver
     * signature check and a few fields succeed.
     * CR32 (PCI config dword at 0x80) is handled via config space;
     * here we only care about 93cx6 behavior used by adm8211_read_eeprom.
     */
    s->use_93c66 = true;
    s->eeprom_addr_bits = 8; /* 256-word device */

    memset(s->eeprom_words_93c66, 0, sizeof(s->eeprom_words_93c66));
    memset(s->eeprom_words_93c46, 0, sizeof(s->eeprom_words_93c46));

    /* Start TSF timer */
    timer_init_ms(&s->tsf_timer, QEMU_CLOCK_VIRTUAL, adm8211_tsf_timer_cb, s);
    timer_mod(&s->tsf_timer, qemu_clock_get_ms(QEMU_CLOCK_VIRTUAL) + 1);

    er_reset(pcibase_reset, DEVICE(pdev));
}

